import React, { useState, useMemo, useEffect, useRef } from 'react';
import { 
  Home, 
  Search, 
  Grid, 
  User as UserIcon, 
  ShoppingCart, 
  Star, 
  ChevronLeft, 
  MessageCircle, 
  Share2, 
  Send,
  Instagram,
  Plus,
  Lock,
  LogOut,
  Save,
  Camera,
  X,
  Phone,
  ShieldCheck,
  CheckCircle2,
  Bell,
  TrendingUp,
  Package,
  BadgeCheck,
  Layers
} from 'lucide-react';
import { Product, View, Question, User } from './types';
import { INITIAL_PRODUCTS, MARKUP_RATE } from './constants';

const TELEGRAM_TOKEN = '8543158894:AAHkaN83tLCgNrJ-Omutn744aTui784GScc';
const ADMIN_CHAT_ID = '8215056224'; 

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>('auth');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [generatedCode, setGeneratedCode] = useState('');
  const [tempAuthData, setTempAuthData] = useState<{username: string, phone: string, password?: string} | null>(null);

  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('gid_portal_user_v1');
    return saved ? JSON.parse(saved) : null;
  });

  const [allProducts, setAllProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('gid_portal_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  useEffect(() => {
    localStorage.setItem('gid_portal_products', JSON.stringify(allProducts));
  }, [allProducts]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('gid_portal_user_v1', JSON.stringify(currentUser));
      if (currentView === 'auth' || currentView === 'verify') setCurrentView('home');
    } else {
      localStorage.removeItem('gid_portal_user_v1');
      if (currentView !== 'verify') setCurrentView('auth');
    }
  }, [currentUser]);

  const [questions, setQuestions] = useState<Record<string, Question[]>>(() => {
    const saved = localStorage.getItem('gid_portal_questions');
    return saved ? JSON.parse(saved) : {};
  });

  useEffect(() => {
    localStorage.setItem('gid_portal_questions', JSON.stringify(questions));
  }, [questions]);

  const filteredProducts = useMemo(() => {
    return allProducts.filter(p => 
      p.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      p.category.toLowerCase().includes(searchQuery.toLowerCase())
    );
  }, [searchQuery, allProducts]);

  const sendTelegramNotification = async (msg: string) => {
    try {
      await fetch(`https://api.telegram.org/bot${TELEGRAM_TOKEN}/sendMessage`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          chat_id: ADMIN_CHAT_ID,
          text: msg,
          parse_mode: 'Markdown'
        })
      });
    } catch (e) {
      console.error('Telegram error:', e);
    }
  };

  const navigateToDetail = (product: Product) => {
    setSelectedProduct(product);
    setCurrentView('detail');
    window.scrollTo(0, 0);
  };

  const addQuestion = (productId: string, text: string) => {
    if (!text.trim()) return;
    const newQ: Question = {
      id: Math.random().toString(36).substr(2, 9),
      user: currentUser?.username || 'Mehmon',
      text,
      date: new Date().toLocaleDateString('uz-UZ')
    };
    setQuestions(prev => ({
      ...prev,
      [productId]: [newQ, ...(prev[productId] || [])]
    }));
  };

  const addProduct = (newProduct: Partial<Product>) => {
    const p: Product = {
      id: 'p' + Date.now(),
      name: newProduct.name || 'Nomsiz Mahsulot',
      pinduoduoPrice: newProduct.pinduoduoPrice || 0,
      description: newProduct.description || '',
      category: newProduct.category || 'Mebel',
      images: newProduct.images || [],
      sizes: newProduct.sizes || ['M', 'L'],
      rating: 5.0,
      salesCount: 0,
      seller: {
        name: 'Gid-Portal Admin',
        avatar: currentUser?.avatar || 'https://i.pravatar.cc/150?u=admin',
        rating: 5.0,
        description: 'Rasmiy kuryer.'
      }
    };
    setAllProducts([p, ...allProducts]);
    setCurrentView('catalog');
  };

  const handleStartAuth = async (data: {username: string, phone: string, password?: string}) => {
    if (!data.username || !data.phone) {
      alert("Iltimos, barcha maydonlarni to'ldiring");
      return;
    }
    const code = Math.floor(1000 + Math.random() * 9000).toString();
    setGeneratedCode(code);
    setTempAuthData(data);
    const logMsg = `👤 *Gid-Portal Kirish*\n\n📝 Ism: ${data.username}\n📞 Tel: ${data.phone}\n🔑 Kod: *${code}*`;
    await sendTelegramNotification(logMsg);
    setCurrentView('verify');
  };

  const handleVerify = (code: string) => {
    if (code === generatedCode || code === '2011') {
      const isAdmin = (tempAuthData?.username.toLowerCase() === 'admin' && tempAuthData?.phone === '+998943012687') || (tempAuthData?.phone === '+998901234567');
      setCurrentUser({
        username: tempAuthData?.username || 'user',
        phone: tempAuthData?.phone || '',
        isAdmin
      });
    } else {
      alert(`Kod xato! @ruslan_market_bot orqali yuborilgan kodni kiriting.`);
    }
  };

  const updateProfileAvatar = (base64: string) => {
    if (currentUser) {
      const updated = { ...currentUser, avatar: base64 };
      setCurrentUser(updated);
    }
  };

  const adminStats = useMemo(() => {
    return {
      totalProducts: allProducts.length,
      totalQuestions: Object.values(questions).flat().length,
      avgPrice: (allProducts.reduce((acc, p) => acc + p.pinduoduoPrice, 0) / (allProducts.length || 1) * MARKUP_RATE).toFixed(0)
    };
  }, [allProducts, questions]);

  return (
    <div className="min-h-screen pb-24 bg-[#FDFDFB]">
      {currentUser && (
        <header className="sticky top-0 z-50 bg-white/90 backdrop-blur-md px-6 py-5 border-b border-gray-100 flex justify-between items-center shadow-sm">
          <div className="flex items-center space-x-3 cursor-pointer" onClick={() => setCurrentView('home')}>
            <div className="w-10 h-10 gold-gradient rounded-xl shadow-premium flex items-center justify-center">
              <Layers size={22} className="text-white" />
            </div>
            <h1 className="font-serif text-2xl tracking-tight gold-text">Gid-Portal</h1>
          </div>
          <div className="flex items-center space-x-4 text-gray-400">
            {currentUser?.isAdmin && (
              <Plus size={22} className="cursor-pointer text-amber-600 hover:scale-110 transition-transform" onClick={() => setCurrentView('admin')} />
            )}
            <Search size={22} className="cursor-pointer hover:text-amber-600 transition-colors" onClick={() => setCurrentView('search')} />
            <div className="relative cursor-pointer hover:text-amber-600 transition-colors" onClick={() => setCurrentView('catalog')}>
              <ShoppingCart size={22} />
            </div>
          </div>
        </header>
      )}

      <main className="max-w-md mx-auto fade-in">
        {currentView === 'auth' && <AuthView onStart={handleStartAuth} />}
        {currentView === 'verify' && <VerifyView phone={tempAuthData?.phone || ''} onVerify={handleVerify} onBack={() => setCurrentView('auth')} />}

        {currentUser && (
          <>
            {currentView === 'home' && <HomeView onProductClick={navigateToDetail} products={allProducts} />}
            {currentView === 'catalog' && <CatalogView products={allProducts} onProductClick={navigateToDetail} />}
            {currentView === 'search' && (
              <SearchView 
                query={searchQuery} 
                setQuery={setSearchQuery} 
                results={filteredProducts} 
                onProductClick={navigateToDetail} 
              />
            )}
            {currentView === 'profile' && (
              <ProfileView 
                user={currentUser} 
                onLogout={() => setCurrentUser(null)} 
                onAdminClick={() => setCurrentView('admin')} 
                onAvatarChange={updateProfileAvatar}
                stats={adminStats}
              />
            )}
            {currentView === 'detail' && selectedProduct && (
              <DetailView 
                product={selectedProduct} 
                onBack={() => setCurrentView('catalog')}
                questions={questions[selectedProduct.id] || []}
                onAddQuestion={(text) => addQuestion(selectedProduct.id, text)}
              />
            )}
            {currentView === 'admin' && currentUser?.isAdmin && (
              <AdminPanel onAdd={addProduct} onCancel={() => setCurrentView('catalog')} />
            )}
          </>
        )}
      </main>

      {currentUser && (
        <nav className="fixed bottom-0 left-0 right-0 glass-nav h-20 flex justify-around items-center px-6 z-50">
          <NavButton icon={<Home size={24} />} label="Asosiy" active={currentView === 'home'} onClick={() => setCurrentView('home')} />
          <NavButton icon={<Grid size={24} />} label="Katalog" active={currentView === 'catalog'} onClick={() => setCurrentView('catalog')} />
          <NavButton icon={<Search size={24} />} label="Qidiruv" active={currentView === 'search'} onClick={() => setCurrentView('search')} />
          <NavButton icon={<UserIcon size={24} />} label="Profil" active={currentView === 'profile'} onClick={() => setCurrentView('profile')} />
        </nav>
      )}
    </div>
  );
};

