const ProfileView = ({ user, onLogout, onAdminClick, onAvatarChange, stats }: any) => {
  const fileRef = useRef<HTMLInputElement>(null);
  const handleAvatarUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => onAvatarChange(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="p-8 space-y-10">
      <div className="flex flex-col items-center">
        <div className="relative mb-6 group">
          <div className="w-32 h-32 rounded-[2.5rem] border-4 border-white shadow-premium overflow-hidden bg-white">
