            <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center cursor-pointer" onClick={() => fileRef.current?.click()}>
              <Camera size={24} className="text-white" />
            </div>
          </div>
          <div className="absolute -bottom-2 -right-2 w-12 h-12 gold-gradient rounded-xl flex items-center justify-center text-white border-4 border-white">
             <BadgeCheck size={20} />
          </div>
          <input type="file" ref={fileRef} className="hidden" accept="image/*" onChange={handleAvatarUpload} />
        </div>
        <div className="text-center">
          <h2 className="text-2xl font-bold tracking-tight">{user.username}</h2>
          <p className="text-gray-400 text-sm font-semibold tracking-wide uppercase mt-1">{user.phone}</p>
        </div>
      </div>

      {user.isAdmin && (
        <div className="grid grid-cols-3 gap-3">
          <div className="bg-white border border-gray-100 p-4 rounded-3xl text-center shadow-sm">
            <Package size={20} className="mx-auto text-amber-600 mb-2" />
            <p className="text-lg font-black">{stats.totalProducts}</p>
            <p className="text-[8px] text-gray-400 uppercase font-bold">Mahsulot</p>
          </div>
          <div className="bg-white border border-gray-100 p-4 rounded-3xl text-center shadow-sm">
            <MessageCircle size={20} className="mx-auto text-blue-500 mb-2" />
            <p className="text-lg font-black">{stats.totalQuestions}</p>
            <p className="text-[8px] text-gray-400 uppercase font-bold">Savollar</p>
          </div>
          <div className="bg-white border border-gray-100 p-4 rounded-3xl text-center shadow-sm">
            <TrendingUp size={20} className="mx-auto text-green-500 mb-2" />
            <p className="text-lg font-black">${stats.avgPrice}</p>
            <p className="text-[8px] text-gray-400 uppercase font-bold">O'rt. Narx</p>
          </div>
        </div>
      )}

      <div className="bg-white rounded-[2.5rem] p-6 shadow-sm border border-gray-100 space-y-3">
