          <button onClick={onAdminClick} className="w-full flex items-center space-x-5 p-5 hover:bg-amber-50 rounded-3xl transition-all group">
            <div className="w-12 h-12 bg-amber-600 rounded-2xl flex items-center justify-center text-white shadow-lg">
              <Plus size={24} />
            </div>
            <div className="text-left flex-1">
              <p className="font-bold text-base">Mahsulot Qo'shish</p>
              <p className="text-[10px] text-gray-400 uppercase font-bold mt-0.5">Admin Panel</p>
            </div>
          </button>
        )}
