const AdminPanel = ({ onAdd, onCancel }: any) => {
  const [formData, setFormData] = useState<Partial<Product>>({ name: '', pinduoduoPrice: 0, description: '', category: 'Mebel', images: [], sizes: ['S', 'M', 'L'] });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: any) => {
    const files = e.target.files;
    if (!files) return;
    Array.from(files).forEach((file: any) => {
      const reader = new FileReader();
      reader.onloadend = () => setFormData(prev => ({ ...prev, images: [...(prev.images || []), reader.result as string] }));
      reader.readAsDataURL(file);
    });
  };

  const addSize = () => {
    const sz = prompt("Yangi o'lcham kiriting (masalan: XL, 42, 12 kishilik):");
    if (sz) setFormData({...formData, sizes: [...(formData.sizes || []), sz]});
  };

  return (
    <div className="p-8 pb-32 space-y-8 fade-in">
      <div className="flex items-center space-x-5">
        <button onClick={onCancel} className="w-10 h-10 bg-white border border-gray-100 rounded-xl flex items-center justify-center"><ChevronLeft size={24} /></button>
        <h2 className="text-3xl font-bold tracking-tight">Yangi Mahsulot</h2>
      </div>

