const AdminPanel = ({ onAdd, onCancel }: any) => {
  const [formData, setFormData] = useState<Partial<Product>>({ name: '', pinduoduoPrice: 0, description: '', category: 'Mebel', images: [], sizes: ['S', 'M', 'L'] });
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: any) => {
    const files = e.target.files;
    if (!files) return;
    Array.from(files).forEach((file: any) => {
      const reader = new FileReader();
      reader.onloadend = () => setFormData(prev => ({ ...prev, images: [...(prev.images || []), reader.result as string] }));
      reader.readAsDataURL(file);
    });
  };

  const addSize = () => {
    const sz = prompt("Yangi o'lcham kiriting (masalan: XL, 42, 12 kishilik):");
    if (sz) setFormData({...formData, sizes: [...(formData.sizes || []), sz]});
  };

  return (
    <div className="p-8 pb-32 space-y-8 fade-in">
      <div className="flex items-center space-x-5">
        <button onClick={onCancel} className="w-10 h-10 bg-white border border-gray-100 rounded-xl flex items-center justify-center"><ChevronLeft size={24} /></button>
        <h2 className="text-3xl font-bold tracking-tight">Yangi Mahsulot</h2>
      </div>

      <div className="space-y-8">
        <div className="space-y-4">
          <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block px-1">PNG Rasmlar</label>
          <div className="grid grid-cols-3 gap-4">
            {formData.images?.map((img, i) => (
              <div key={i} className="relative aspect-square rounded-[1.5rem] overflow-hidden group shadow-sm bg-gray-50 border border-gray-100 flex items-center justify-center p-3">
                <img src={img} className="max-w-full max-h-full object-contain" />
                <button onClick={() => setFormData({...formData, images: formData.images?.filter((_, idx) => idx !== i)})} className="absolute top-2 right-2 bg-black/60 text-white rounded-full p-1.5"><X size={12} /></button>
              </div>
            ))}
            <button onClick={() => fileInputRef.current?.click()} className="aspect-square border-2 border-dashed border-gray-200 rounded-[1.5rem] flex flex-col items-center justify-center text-gray-400 bg-white">
              <Camera size={32} />
              <span className="text-[9px] mt-2 font-bold uppercase">Rasm yuklash</span>
            </button>
          </div>
          <input type="file" ref={fileInputRef} onChange={handleFileChange} multiple accept="image/png" className="hidden" />
        </div>

        <div className="space-y-6">
          <Input label="Mahsulot Nomi" value={formData.name} onChange={(v:any) => setFormData({...formData, name: v})} />
          <div className="grid grid-cols-2 gap-5">
            <Input label="Platforma Narxi ($)" type="number" value={formData.pinduoduoPrice || ''} onChange={(v:any) => setFormData({...formData, pinduoduoPrice: Number(v)})} />
            <div className="space-y-2">
              <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block px-1">Sotuv Narxi</label>
              <div className="bg-amber-50 border border-amber-100 p-5 rounded-3xl font-black text-amber-700 h-[64px] flex items-center shadow-inner text-xl">
                ${(formData.pinduoduoPrice || 0) * MARKUP_RATE}
              </div>
            </div>
          </div>

          <div className="space-y-4">
            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block px-1">O'lchamlar (Razmerlar)</label>
            <div className="flex flex-wrap gap-2">
              {formData.sizes?.map((s, i) => (
                <div key={i} className="bg-gray-100 px-4 py-2 rounded-xl text-sm font-bold flex items-center space-x-2">
                  <span>{s}</span>
                  <button onClick={() => setFormData({...formData, sizes: formData.sizes?.filter((_, idx) => idx !== i)})} className="text-red-400"><X size={14}/></button>
                </div>
              ))}
              <button onClick={addSize} className="border-2 border-dashed border-amber-200 text-amber-600 px-4 py-2 rounded-xl text-sm font-bold flex items-center space-x-1">
                <Plus size={14}/> <span>Qo'shish</span>
              </button>
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest block px-1">Kategoriya</label>
            <select className="w-full bg-white border border-gray-100 rounded-[1.5rem] p-5 shadow-sm outline-none appearance-none cursor-pointer" value={formData.category} onChange={e => setFormData({...formData, category: e.target.value})}>
              {['Mebel', 'Oshxona', 'Aksessuarlar', 'Elektronika', 'Kiyim-kechak', 'Sport', 'Go\'zallik'].map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <textarea className="w-full bg-white border border-gray-100 rounded-[1.5rem] p-6 h-40 shadow-sm outline-none resize-none transition-all text-base" placeholder="Tavsif..." value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} />
