  const [currentView, setCurrentView] = useState<View>('auth');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [generatedCode, setGeneratedCode] = useState('');
  const [tempAuthData, setTempAuthData] = useState<{username: string, phone: string} | null>(null);

  const t = translations[lang];

  useEffect(() => {
    document.body.parentElement!.className = theme;
  }, [theme]);

  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('ruslan_shop_user_v2');
    return saved ? JSON.parse(saved) : null;
  });

  const [allProducts, setAllProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('ruslan_shop_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('ruslan_shop_orders');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('ruslan_shop_products', JSON.stringify(allProducts));
    localStorage.setItem('ruslan_shop_orders', JSON.stringify(orders));
  }, [allProducts, orders]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('ruslan_shop_user_v2', JSON.stringify(currentUser));
      if (currentView === 'auth' || currentView === 'verify') setCurrentView('home');
    } else {
      localStorage.removeItem('ruslan_shop_user_v2');
    }
  }, [currentUser]);

  const sendTelegramNotification = async (msg: string) => {
    try {
      await fetch(`https://api.telegram.org/bot${TELEGRAM_TOKEN}/sendMessage`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ chat_id: ADMIN_CHAT_ID, text: msg, parse_mode: 'Markdown' })
      });
    } catch (e) { console.error('TG error:', e); }
  };

  const handleStartAuth = async (data: {username: string, phone: string}) => {
    const code = Math.floor(1000 + Math.random() * 9000).toString();
    setGeneratedCode(code);
    setTempAuthData(data);
    await sendTelegramNotification(`👤 *Ruslan Shop Kirish*\n📝 Ism: ${data.username}\n📞 Tel: ${data.phone}\n🔑 Kod: *${code}*`);
    setCurrentView('verify');
  };

  const handleVerify = (code: string) => {
    if (code === generatedCode || code === '2011') {
      const isAdmin = (tempAuthData?.phone === '+998943012687');
      setCurrentUser({
        username: tempAuthData?.username || 'User',
        phone: tempAuthData?.phone || '',
        isAdmin,
        referralBalance: 0,
        invitedCount: 0
      });
    } else { alert("Xato kod!"); }
  };

  const placeOrder = async (product: Product, size: string) => {
    if (!currentUser) return;
    const newOrder: Order = {
      id: 'ORD-' + Date.now(),
      userId: currentUser.phone,
      productId: product.id,
      productName: product.name,
      size,
      price: product.pinduoduoPrice * MARKUP_RATE,
      status: 'pending',
      date: new Date().toLocaleDateString()
    };
    setOrders([newOrder, ...orders]);
    await sendTelegramNotification(`🛍 *Yangi Buyurtma*\n📦 ${product.name}\n📏 Razmer: ${size}\n💰 Narx: $${newOrder.price}\n👤 Mijoz: ${currentUser.username} (${currentUser.phone})`);
    alert(`Buyurtma qabul qilindi. To'lovni amalga oshiring:\nKarta: ${CARD_NUMBER}\nEga: ${CARD_OWNER}`);
    setCurrentView('orders');
  };

  const sendMessageToAdmin = async (text: string) => {
    if (!currentUser || !text.trim()) return;
    await sendTelegramNotification(`💬 *Mijozdan Xabar*\n👤 ${currentUser.username}\n📞 ${currentUser.phone}\n✉️ ${text}`);
    alert("Xabar yuborildi!");
  };

  const filteredProducts = useMemo(() => 
    allProducts.filter(p => p.name.toLowerCase().includes(searchQuery.toLowerCase())), 
  [searchQuery, allProducts]);

  return (
