const AdminPanel = ({ onAdd, onCancel }: any) => {
  const [fd, setFd] = useState({ name: '', price: 0, desc: '', sizes: 'S, M, L' });
  const [imgs, setImgs] = useState<string[]>([]);
  const [video, setVideo] = useState<string>('');

  const imgInputRef = useRef<HTMLInputElement>(null);
  const videoInputRef = useRef<HTMLInputElement>(null);

  const handleImgs = (e: React.ChangeEvent<HTMLInputElement>) => {
    const fileList = e.target.files;
    if (!fileList) return;
    const files = Array.from(fileList) as File[];
    files.forEach((file: File) => {
      const reader = new FileReader();
      reader.onloadend = () => setImgs(prev => [...prev, reader.result as string].slice(0, 5));
      reader.readAsDataURL(file);
    });
  };

  const handleVideo = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setVideo(reader.result as string);
      reader.readAsDataURL(file as Blob);
    }
  };

  const save = () => {
    if (!fd.name || !fd.price || imgs.length === 0) {
      alert("Nomi, narxi va kamida 1 ta rasm shart!");
      return;
    }
    onAdd({
      id: 'P-' + Date.now(),
      name: fd.name,
      pinduoduoPrice: fd.price,
      description: fd.desc,
      sizes: fd.sizes.split(',').map(s => s.trim()),
      images: imgs,
      video: video,
      category: 'Shop', rating: 5, salesCount: 0, 
      seller: { name: 'Ruslan Shop', avatar: '', rating: 5, description: '' }
    });
  };

  return (
    <div className="p-8 space-y-6 pb-24">
      <div className="flex items-center space-x-4">
        <button onClick={onCancel} className="p-2 bg-gray-100/10 rounded-xl active:scale-90 transition-all"><ChevronLeft size={20}/></button>
        <h2 className="text-2xl font-bold tracking-tight">Yangi Mahsulot</h2>
      </div>

      <div className="space-y-2">
        <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Rasmlar (maks 5 ta)</label>
        <div className="grid grid-cols-3 gap-2">
          {imgs.map((im, i) => (
            <div key={i} className="relative w-full aspect-square rounded-xl overflow-hidden shadow-sm">
              <img src={im} className="w-full h-full object-cover" />
              <button onClick={() => setImgs(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-1 right-1 bg-black/50 text-white rounded-full p-1"><X size={10} /></button>
            </div>
          ))}
          {imgs.length < 5 && (
            <button onClick={() => imgInputRef.current?.click()} className="aspect-square bg-gray-100/10 border-2 border-dashed border-gray-400/20 rounded-xl flex items-center justify-center text-gray-400 active:bg-gray-200/20 transition-all"><Camera size={24} /></button>
          )}
        </div>
        <input type="file" ref={imgInputRef} multiple accept="image/*" className="hidden" onChange={handleImgs} />
      </div>

      <div className="space-y-2">
        <label className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Video (ixtiyoriy 1 ta)</label>
        {video ? (
          <div className="relative w-full h-32 bg-black rounded-xl overflow-hidden shadow-lg">
             <video src={video} className="w-full h-full object-contain" />
             <button onClick={() => setVideo('')} className="absolute top-2 right-2 bg-black/50 text-white rounded-full p-1"><X size={14} /></button>
          </div>
        ) : (
          <button onClick={() => videoInputRef.current?.click()} className="w-full h-16 bg-gray-100/10 border-2 border-dashed border-gray-400/20 rounded-xl flex items-center justify-center text-gray-400 gap-2 font-bold uppercase text-[10px] active:bg-gray-200/20 transition-all"><Video size={20} /> Video yuklash</button>
        )}
        <input type="file" ref={videoInputRef} accept="video/*" className="hidden" onChange={handleVideo} />
      </div>

      <div className="space-y-4">
        <input className="w-full bg-gray-100/10 border border-gray-100/10 p-4 rounded-xl outline-none" placeholder="Mahsulot nomi" value={fd.name} onChange={e=>setFd({...fd, name: e.target.value})} />
        <input type="number" className="w-full bg-gray-100/10 border border-gray-100/10 p-4 rounded-xl outline-none" placeholder="Narxi ($)" value={fd.price} onChange={e=>setFd({...fd, price: Number(e.target.value)})} />
        <input className="w-full bg-gray-100/10 border border-gray-100/10 p-4 rounded-xl outline-none" placeholder="Razmerlar (vergul bilan)" value={fd.sizes} onChange={e=>setFd({...fd, sizes: e.target.value})} />
        <textarea className="w-full bg-gray-100/10 border border-gray-100/10 p-4 rounded-xl h-24 outline-none" placeholder="Tavsif" value={fd.desc} onChange={e=>setFd({...fd, desc: e.target.value})} />
      </div>

      <button onClick={save} className="w-full py-5 gold-gradient text-white font-bold rounded-2xl shadow-premium uppercase text-xs tracking-widest active:scale-[0.98] transition-all">Do'konga joylash</button>
    </div>
  );
};

const ProductCard = ({ product, onClick }: any) => (
  <div onClick={onClick} className="bg-gray-100/10 rounded-2xl overflow-hidden border border-gray-100/10 flex flex-col group active:scale-95 transition-all shadow-sm">
    <div className="h-44 png-container relative flex items-center justify-center p-4">
