);

const SearchView = ({ t, query, setQuery, results, onProductClick }: any) => (
  <div className="p-6 pb-24">
    <div className="relative mb-6">
      <input 
        className="w-full bg-gray-100/10 border border-gray-100/10 p-4 pl-12 rounded-2xl outline-none shadow-sm focus:ring-1 focus:ring-amber-500/30 transition-all" 
        placeholder="Mahsulot qidirish..." 
        value={query} 
        onChange={e => setQuery(e.target.value)} 
      />
      <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={20} />
    </div>
    <div className="grid grid-cols-2 gap-4">
      {results.map((p: any) => <ProductCard key={p.id} product={p} onClick={() => onProductClick(p)} />)}
    </div>
  </div>
);

