const AdminPanel = ({ onAdd, onCancel }: any) => {
  const [fd, setFd] = useState({ name: '', price: 0, desc: '', sizes: 'S, M, L' });
  const [imgs, setImgs] = useState<string[]>([]);
  const [video, setVideo] = useState<string>('');
  const imgInputRef = useRef<HTMLInputElement>(null);
  const handleImgs = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    files.forEach((file: File) => {
      const reader = new FileReader();
      reader.onloadend = () => setImgs(prev => [...prev, reader.result as string].slice(0, 5));
      reader.readAsDataURL(file);
    });
  };
  const save = () => {
    if (!fd.name || !fd.price || imgs.length === 0) return alert("Xatolik!");
    onAdd({ id: 'P-' + Date.now(), name: fd.name, pinduoduoPrice: fd.price, description: fd.desc, sizes: fd.sizes.split(','), images: imgs, video, category: 'Shop', rating: 5, salesCount: 0, seller: { name: 'Ruslan Shop', avatar: '', rating: 5, description: '' } });
  };
  return (
    <div className="p-8 space-y-6">
      <div className="flex items-center space-x-4"><button onClick={onCancel} className="p-2 bg-gray-100/10 rounded-xl"><ChevronLeft size={20}/></button><h2 className="text-2xl font-bold">Yangi Mahsulot</h2></div>
      <div className="grid grid-cols-3 gap-2">
        {imgs.map((im, i) => <img key={i} src={im} className="w-full aspect-square object-cover rounded-xl" />)}
        {imgs.length < 5 && <button onClick={() => imgInputRef.current?.click()} className="aspect-square bg-gray-100/10 border-2 border-dashed border-gray-400/20 rounded-xl flex items-center justify-center"><Camera size={24} /></button>}
      </div>
      <input type="file" ref={imgInputRef} multiple className="hidden" onChange={handleImgs} />
      <input className="w-full bg-gray-100/10 border border-gray-100/10 p-4 rounded-xl outline-none" placeholder="Nomi" value={fd.name} onChange={e=>setFd({...fd, name: e.target.value})} />
      <input type="number" className="w-full bg-gray-100/10 border border-gray-100/10 p-4 rounded-xl outline-none" placeholder="Narxi ($)" value={fd.price} onChange={e=>setFd({...fd, price: Number(e.target.value)})} />
      <button onClick={save} className="w-full py-5 gold-gradient text-white font-bold rounded-2xl shadow-xl">Saqlash</button>
    </div>
  );
};

