const HomeView = ({ t, products, onProductClick }: any) => (
  <div className="p-6 space-y-8">
    <div className="gold-gradient rounded-3xl p-8 text-white shadow-xl relative overflow-hidden">
      <h2 className="text-3xl font-serif font-black mb-2">Ruslan Shop</h2>
      <p className="text-white/80 text-xs mb-6 uppercase tracking-widest">{t.mallDesc}</p>
      <button onClick={() => window.scrollTo({ top: 500, behavior: 'smooth' })} className="bg-white text-amber-700 px-6 py-2 rounded-full font-bold text-xs uppercase shadow-lg">Boshlash</button>
    </div>
    <div className="grid grid-cols-2 gap-4">
      {products.map((p: any) => <ProductCard key={p.id} product={p} onClick={() => onProductClick(p)} />)}
