  const [msg, setMsg] = useState('');
  return (
    <div className="p-8 space-y-8">
      <div className="flex flex-col items-center relative">
        <div className="w-28 h-28 rounded-full border-4 border-amber-500/20 p-1 mb-4 relative shadow-premium overflow-hidden">
          {user.isAdmin ? <SupportAvatar /> : <img src={`https://i.pravatar.cc/150?u=${user.phone}`} className="w-full h-full rounded-full object-cover" />}
        </div>
        <h2 className="text-xl font-bold uppercase tracking-tight">{user.username}</h2>
        <p className="text-gray-400 text-xs font-mono">{user.phone}</p>
        <div className="mt-2 flex items-center gap-1.5 text-xs text-amber-500 font-bold uppercase tracking-widest bg-amber-500/5 px-3 py-1 rounded-full border border-amber-500/10">
           <Clock size={12} /> {t.support247}
        </div>
      </div>

