const AdminPanel = ({ onAdd, onCancel }: any) => {
  const [fd, setFd] = useState({ name: '', price: 0, desc: '', sizes: 'S, M, L' });
  const [imgs, setImgs] = useState<string[]>([]);
  const [vids, setVids] = useState<string[]>([]);

  const imgInputRef = useRef<HTMLInputElement>(null);
  const vidInputRef = useRef<HTMLInputElement>(null);

  const handleImgs = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    files.forEach((file: File) => {
      const reader = new FileReader();
      reader.onloadend = () => setImgs(prev => [...prev, reader.result as string].slice(0, 5));
      reader.readAsDataURL(file);
    });
  };

  const handleVids = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    files.forEach((file: File) => {
      const reader = new FileReader();
      reader.onloadend = () => setVids(prev => [...prev, reader.result as string].slice(0, 3));
      reader.readAsDataURL(file);
    });
  };

  const save = () => {
    if (!fd.name || !fd.price || imgs.length < 4) return alert("Kamida 4 ta rasm va nomi/narxi shart!");
    onAdd({ 
      id: 'P-' + Date.now(), 
      name: fd.name, 
      pinduoduoPrice: fd.price, 
      description: fd.desc, 
      sizes: fd.sizes.split(','), 
      images: imgs, 
      videos: vids, 
      category: 'Shop', 
      rating: 5, 
      salesCount: 0, 
      seller: { name: 'Ruslan Shop', avatar: '', rating: 5, description: '' } 
    });
  };

  return (
    <div className="p-8 space-y-6">
      <div className="flex items-center space-x-4">
        <button onClick={onCancel} className="p-2 bg-gray-100/10 rounded-xl"><ChevronLeft size={20}/></button>
        <h2 className="text-2xl font-bold">Yangi Mahsulot</h2>
      </div>

      <div className="space-y-4">
        <label className="text-xs font-bold text-gray-400 uppercase tracking-widest">Rasmlar (4-5 ta)</label>
        <div className="grid grid-cols-3 gap-2">
          {imgs.map((im, i) => (
            <div key={i} className="relative aspect-square">
              <img src={im} className="w-full h-full object-cover rounded-xl" />
              <button onClick={() => setImgs(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-1 right-1 p-1 bg-red-500 text-white rounded-full"><X size={10}/></button>
            </div>
          ))}
          {imgs.length < 5 && (
            <button onClick={() => imgInputRef.current?.click()} className="aspect-square bg-gray-100/10 border-2 border-dashed border-gray-400/20 rounded-xl flex items-center justify-center">
              <Camera size={24} />
            </button>
          )}
        </div>
        <input type="file" ref={imgInputRef} multiple className="hidden" accept="image/*" onChange={handleImgs} />
      </div>

      <div className="space-y-4">
        <label className="text-xs font-bold text-gray-400 uppercase tracking-widest">Videolar (1-3 ta)</label>
        <div className="grid grid-cols-3 gap-2">
          {vids.map((vd, i) => (
            <div key={i} className="relative aspect-square bg-black rounded-xl overflow-hidden">
              <video src={vd} className="w-full h-full object-contain" />
              <button onClick={() => setVids(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-1 right-1 p-1 bg-red-500 text-white rounded-full"><X size={10}/></button>
            </div>
          ))}
          {vids.length < 3 && (
            <button onClick={() => vidInputRef.current?.click()} className="aspect-square bg-gray-100/10 border-2 border-dashed border-gray-400/20 rounded-xl flex items-center justify-center">
              <Video size={24} />
            </button>
          )}
        </div>
        <input type="file" ref={vidInputRef} multiple className="hidden" accept="video/*" onChange={handleVids} />
      </div>

      <input className="w-full bg-gray-100/10 border border-gray-100/10 p-4 rounded-xl outline-none" placeholder="Nomi" value={fd.name} onChange={e=>setFd({...fd, name: e.target.value})} />
      <input type="number" className="w-full bg-gray-100/10 border border-gray-100/10 p-4 rounded-xl outline-none" placeholder="Narxi ($)" value={fd.price} onChange={e=>setFd({...fd, price: Number(e.target.value)})} />
      <textarea className="w-full bg-gray-100/10 border border-gray-100/10 p-4 rounded-xl outline-none h-24" placeholder="Tavsif" value={fd.desc} onChange={e=>setFd({...fd, desc: e.target.value})} />
      <input className="w-full bg-gray-100/10 border border-gray-100/10 p-4 rounded-xl outline-none" placeholder="O'lchamlar (S,M,L)" value={fd.sizes} onChange={e=>setFd({...fd, sizes: e.target.value})} />

      <button onClick={save} className="w-full py-5 gold-gradient text-white font-bold rounded-2xl shadow-xl">Saqlash</button>
    </div>
  );
};

