const App: React.FC = () => {
  const [lang, setLang] = useState<Language>('uz');
  const [theme, setTheme] = useState<'light' | 'dark'>('light');
  const [currentView, setCurrentView] = useState<View>('auth');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [generatedCode, setGeneratedCode] = useState('');
  const [tempAuthData, setTempAuthData] = useState<{username: string, phone: string, code?: string} | null>(null);

  const t = translations[lang];

  useEffect(() => {
    document.body.parentElement!.className = theme;
  }, [theme]);

  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('ruslan_shop_user_v5');
    return saved ? JSON.parse(saved) : null;
  });

  const [allProducts, setAllProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('ruslan_shop_products_v5');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('ruslan_shop_orders_v5');
    return saved ? JSON.parse(saved) : [];
  });

  const [userMessages, setUserMessages] = useState<UserMessage[]>(() => {
    const saved = localStorage.getItem('ruslan_shop_messages_v5');
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem('ruslan_shop_products_v5', JSON.stringify(allProducts));
  }, [allProducts]);

  useEffect(() => {
    localStorage.setItem('ruslan_shop_orders_v5', JSON.stringify(orders));
  }, [orders]);

  useEffect(() => {
    localStorage.setItem('ruslan_shop_messages_v5', JSON.stringify(userMessages));
  }, [userMessages]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem('ruslan_shop_user_v5', JSON.stringify(currentUser));
      if (currentView === 'auth' || currentView === 'verify') setCurrentView('home');
    } else {
      localStorage.removeItem('ruslan_shop_user_v5');
    }
  }, [currentUser]);

  useEffect(() => {
    const timer = setInterval(() => {
      let changed = false;
      const now = Date.now();
      const updatedOrders = orders.map(order => {
        if (order.status === 'pending' && (now - order.timestamp) > 20000) {
          changed = true;
          return { ...order, status: 'verifying' as const };
        }
        return order;
      });
      if (changed) setOrders(updatedOrders);
    }, 1000);
    return () => clearInterval(timer);
  }, [orders]);

  const sendTelegramNotification = async (msg: string) => {
    try {
      await fetch(`https://api.telegram.org/bot${TELEGRAM_TOKEN}/sendMessage`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ chat_id: ADMIN_CHAT_ID, text: msg, parse_mode: 'Markdown' })
      });
    } catch (e) { console.error('TG error:', e); }
  };

  const handleStartAuth = async (data: {username: string, phone: string, code?: string}) => {
    const isLoggingAsAdmin = data.username.toLowerCase() === 'admin';
    const phoneClean = data.phone.replace(/[^0-9]/g, '');
    const isAdminNum = phoneClean.endsWith(ADMIN_PHONE_MATCH);

    if (isLoggingAsAdmin) {
      if (data.code === ADMIN_SECRET_CODE) {
        setCurrentUser({
          username: data.username,
          phone: data.phone,
          isAdmin: true,
          referralBalance: 0,
          invitedCount: 0
        });
        return;
      } else {
        alert("Admin kodi noto'g'ri!");
        return;
      }
    }

    const code = isAdminNum ? ADMIN_SECRET_CODE : Math.floor(1000 + Math.random() * 9000).toString();
    setGeneratedCode(code);
    setTempAuthData(data);
    await sendTelegramNotification(`👤 *Ruslan Shop Kirish*\n📝 Ism: ${data.username}\n📞 Tel: ${data.phone}\n🔑 Kod: *${code}*`);
    setCurrentView('verify');
  };

  const handleVerify = (code: string) => {
    const phoneClean = tempAuthData?.phone.replace(/[^0-9]/g, '') || '';
    const isAdminNum = phoneClean.endsWith(ADMIN_PHONE_MATCH);
    if (code === generatedCode || (isAdminNum && code === ADMIN_SECRET_CODE)) {
      setCurrentUser({
        username: tempAuthData?.username || 'User',
        phone: tempAuthData?.phone || '',
        isAdmin: isAdminNum,
        referralBalance: 0,
        invitedCount: 0
      });
    } else { alert("Xato kod!"); }
  };

  const placeOrder = async (product: Product, size: string) => {
    if (!currentUser) return;
    const newOrder: Order = {
      id: 'ORD-' + Date.now(),
      userId: currentUser.phone,
      username: currentUser.username,
      productId: product.id,
      productName: product.name,
      size,
      price: product.pinduoduoPrice * MARKUP_RATE,
      status: 'pending',
      date: new Date().toLocaleDateString(),
      timestamp: Date.now()
    };
    setOrders([newOrder, ...orders]);
    await sendTelegramNotification(`🛍 *Yangi Buyurtma*\n📦 ${product.name}\n📏 Razmer: ${size}\n💰 Narx: $${newOrder.price}\n👤 Mijoz: ${currentUser.username} (${currentUser.phone})`);
    alert(`Buyurtma qabul qilindi. To'lovni amalga oshiring:\nKarta: ${CARD_NUMBER}\nEga: ${CARD_OWNER}`);
    setCurrentView('orders');
  };

  const handleManualOrder = (orderData: Partial<Order>) => {
    const newOrder: Order = {
      id: 'ORD-M-' + Date.now(),
      userId: orderData.userId || 'Unknown',
      username: orderData.username || 'Manual Client',
      productId: orderData.productId || 'none',
      productName: orderData.productName || 'Custom Product',
      size: orderData.size || 'N/A',
      price: orderData.price || 0,
      status: 'paid',
      date: new Date().toLocaleDateString(),
      timestamp: Date.now()
    };
    setOrders([newOrder, ...orders]);
    alert("Buyurtma muvaffaqiyatli qo'shildi!");
    setCurrentView('manage_orders');
  };

  const sendMessageToAdmin = async (text: string) => {
    if (!currentUser || !text.trim()) return;
    const newMessage: UserMessage = {
      id: 'MSG-' + Date.now(),
      userId: currentUser.phone,
      username: currentUser.username,
      text,
      date: new Date().toLocaleString()
    };
    setUserMessages([newMessage, ...userMessages]);
    await sendTelegramNotification(`💬 *Mijozdan Xabar*\n👤 ${currentUser.username}\n📞 ${currentUser.phone}\n✉️ ${text}`);
    alert("Xabar yuborildi!");
  };

  const adminReply = async (msgId: string, replyText: string) => {
    const updated = userMessages.map(m => m.id === msgId ? { ...m, reply: replyText } : m);
    setUserMessages(updated);
    alert("Javob yuborildi!");
  };

  const updateOrderStatus = (orderId: string, status: Order['status'], track?: string) => {
    const updated = orders.map(o => o.id === orderId ? { ...o, status, trackNumber: track || o.trackNumber } : o);
    setOrders(updated);
    alert("Buyurtma holati yangilandi!");
  };

  const filteredProducts = useMemo(() => 
    allProducts.filter(p => p.name.toLowerCase().includes(searchQuery.toLowerCase())), 
  [searchQuery, allProducts]);

  return (
    <div className={`min-h-screen pb-24 transition-colors ${theme === 'dark' ? 'bg-[#121212] text-white' : 'bg-[#FDFDFB] text-gray-900'}`}>
      {currentUser && (
        <header className="sticky top-0 z-50 bg-inherit/90 backdrop-blur-md px-6 py-4 border-b border-gray-100/10 flex justify-between items-center">
          <div className="flex items-center space-x-3 cursor-pointer" onClick={() => setCurrentView('home')}>
            <div className="w-9 h-9 gold-gradient rounded-lg flex items-center justify-center shadow-lg"><Layers size={20} className="text-white" /></div>
            <h1 className="font-serif text-xl tracking-tight gold-text font-bold">Ruslan Shop</h1>
          </div>
          <div className="flex items-center space-x-3">
            <button onClick={() => setTheme(theme === 'light' ? 'dark' : 'light')} className="p-2 rounded-lg bg-gray-100/10"><Sun size={18} className={theme === 'light' ? 'text-amber-500' : 'hidden'} /><Moon size={18} className={theme === 'dark' ? 'text-amber-300' : 'hidden'} /></button>
            <button onClick={() => setLang(lang === 'uz' ? 'ru' : lang === 'ru' ? 'en' : 'uz')} className="p-2 rounded-lg bg-gray-100/10 flex items-center space-x-1"><Globe size={18} /> <span className="text-[10px] font-bold uppercase">{lang}</span></button>
            {currentUser.isAdmin && (
              <button onClick={() => setCurrentView('manage_orders')} className="p-2 text-amber-500 hover:scale-110 transition-transform"><Settings size={20} /></button>
            )}
            {currentUser.isAdmin && (
               <button onClick={() => setCurrentView('admin')} className="p-2 text-green-500 hover:scale-110 transition-transform"><Plus size={20} /></button>
            )}
          </div>
        </header>
      )}

      <main className="max-w-md mx-auto fade-in">
        {currentView === 'auth' && <AuthView t={t} onStart={handleStartAuth} />}
        {currentView === 'verify' && <VerifyView t={t} onVerify={handleVerify} onBack={() => setCurrentView('auth')} />}

        {currentUser && (
          <>
            {currentView === 'home' && <HomeView t={t} onProductClick={(p:any) => { setSelectedProduct(p); setCurrentView('detail'); }} products={allProducts} />}
            {currentView === 'catalog' && <CatalogView t={t} products={allProducts} onProductClick={(p:any) => { setSelectedProduct(p); setCurrentView('detail'); }} />}
            {currentView === 'search' && <SearchView t={t} query={searchQuery} setQuery={setSearchQuery} results={filteredProducts} onProductClick={(p:any) => { setSelectedProduct(p); setCurrentView('detail'); }} />}
            {currentView === 'profile' && <ProfileView t={t} user={currentUser} onLogout={() => setCurrentUser(null)} onNavigate={setCurrentView} onSendMsg={sendMessageToAdmin} messages={userMessages.filter(m => m.userId === currentUser.phone)} />}
            {currentView === 'orders' && <OrdersView t={t} orders={orders.filter(o => o.userId === currentUser.phone)} />}
            {currentView === 'referral' && <ReferralView t={t} user={currentUser} />}
            {currentView === 'detail' && selectedProduct && <DetailView t={t} product={selectedProduct} onBack={() => setCurrentView('catalog')} onBuy={(sz:string) => placeOrder(selectedProduct, sz)} onSendMsg={sendMessageToAdmin} />}
            {currentView === 'admin' && currentUser.isAdmin && <AdminPanel t={t} onAdd={(p:any) => { setAllProducts([p, ...allProducts]); setCurrentView('catalog'); }} onCancel={() => setCurrentView('catalog')} />}
            {currentView === 'manage_orders' && currentUser.isAdmin && <ManageOrdersView t={t} orders={orders} onUpdate={updateOrderStatus} onGoMessages={() => setCurrentView('messages')} onAddManual={() => setCurrentView('add_manual_order')} />}
            {currentView === 'messages' && currentUser.isAdmin && <AdminMessagesView t={t} messages={userMessages} onReply={adminReply} onBack={() => setCurrentView('manage_orders')} />}
            {currentView === 'add_manual_order' && currentUser.isAdmin && <AddManualOrderView t={t} products={allProducts} onSave={handleManualOrder} onBack={() => setCurrentView('manage_orders')} />}
          </>
        )}
      </main>

      {currentUser && (
        <nav className="fixed bottom-0 left-0 right-0 glass-nav h-20 flex justify-around items-center px-6 z-50">
          <NavButton icon={<Home size={22} />} label={t.home} active={currentView === 'home'} onClick={() => setCurrentView('home')} />
          <NavButton icon={<Grid size={22} />} label={t.catalog} active={currentView === 'catalog'} onClick={() => setCurrentView('catalog')} />
          <NavButton icon={<Ticket size={22} />} label={t.orders} active={currentView === 'orders'} onClick={() => setCurrentView('orders')} />
          <NavButton icon={<UserIcon size={22} />} label={t.profile} active={currentView === 'profile' || currentView === 'referral'} onClick={() => setCurrentView('profile')} />
        </nav>
      )}
    </div>
  );
};

/* --- Components --- */

const SupportAvatar = () => (
  <div className="w-full h-full bg-white flex flex-col items-center justify-center rounded-full shadow-inner border border-gray-100">
