  const isAdminRequest = username.toLowerCase() === 'admin';

  return (
    <div className="p-8 min-h-screen flex flex-col justify-center text-center">
      <div className="w-20 h-20 gold-gradient rounded-2xl mx-auto mb-6 flex items-center justify-center shadow-xl"><Layers size={40} className="text-white" /></div>
      <h2 className="text-3xl font-serif gold-text font-black mb-2">Ruslan Shop</h2>
      <p className="text-gray-400 text-xs font-bold uppercase tracking-widest mb-10">{t.mallDesc}</p>
      <div className="space-y-4">
        <input className="w-full bg-gray-100/10 border border-gray-200/20 rounded-xl p-4 outline-none" placeholder="Ism..." value={username} onChange={e => setUsername(e.target.value)} />
        <input className="w-full bg-gray-100/10 border border-gray-200/20 rounded-xl p-4 outline-none" placeholder="+998" value={phone} onChange={e => setPhone(e.target.value)} />

