const DetailView = ({ t, product, onBack, onBuy, onSendMsg }: any) => {
  const [activeMedia, setActiveMedia] = useState(0);
  const [sz, setSz] = useState(product.sizes[0]);
  const [msg, setMsg] = useState('');

  const mediaItems = useMemo(() => {
    const items = [...product.images];
    if (product.videos && product.videos.length > 0) items.push(...product.videos);
    return items;
  }, [product]);

  return (
    <div className="min-h-screen bg-inherit">
      <div className="h-[400px] png-container relative flex items-center justify-center overflow-hidden bg-gray-50/50">
        {mediaItems[activeMedia]?.startsWith('data:video') ? (
          <video src={mediaItems[activeMedia]} controls autoPlay className="max-w-full max-h-full object-contain" />
        ) : (
          <img src={mediaItems[activeMedia]} className="max-w-full max-h-full object-contain drop-shadow-2xl transition-all duration-300" />
        )}
        <button onClick={onBack} className="absolute top-6 left-6 p-3 bg-white/20 backdrop-blur rounded-xl z-10"><ChevronLeft size={24} /></button>

        {mediaItems.length > 1 && (
          <div className="absolute bottom-14 left-0 right-0 flex justify-center gap-2 px-6 overflow-x-auto py-2 scrollbar-hide">
            {mediaItems.map((item, idx) => (
              <button 
                key={idx} 
                onClick={() => setActiveMedia(idx)}
                className={`w-12 h-12 rounded-lg border-2 flex-shrink-0 overflow-hidden ${activeMedia === idx ? 'border-amber-500' : 'border-white/20 opacity-60'}`}
              >
                {item.startsWith('data:video') ? (
                  <div className="w-full h-full bg-black flex items-center justify-center"><Play size={12} className="text-white" /></div>
                ) : (
                  <img src={item} className="w-full h-full object-cover" />
                )}
              </button>
            ))}
          </div>
        )}
      </div>

      <div className="p-8 -mt-10 rounded-t-[3rem] bg-inherit border-t border-gray-100/10 space-y-6 relative z-20 shadow-[0_-20px_40px_rgba(0,0,0,0.1)]">
        <div className="flex justify-between items-start">
          <h1 className="text-2xl font-bold flex-1">{product.name}</h1>
          <div className="flex items-center space-x-1 text-amber-500 bg-amber-500/10 px-2 py-1 rounded-lg">
            <Star size={14} fill="currentColor" />
            <span className="text-xs font-bold">{product.rating}</span>
          </div>
        </div>
        <p className="text-4xl font-black gold-text">${product.pinduoduoPrice * MARKUP_RATE}</p>
        <div className="flex flex-wrap gap-2">
          {product.sizes.map((s:any) => <button key={s} onClick={() => setSz(s)} className={`px-4 py-2 rounded-xl font-bold border transition-all ${sz === s ? 'gold-gradient text-white border-transparent shadow-lg scale-105' : 'border-gray-100/10'}`}>{s}</button>)}
        </div>
        <p className="text-gray-400 text-sm leading-relaxed">{product.description}</p>
        <div className="bg-gray-100/10 p-5 rounded-3xl border border-gray-100/10 space-y-4">
          <h3 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest text-center">{t.contact}</h3>
          <div className="flex gap-2">
            <input className="flex-1 bg-inherit border border-gray-100/20 p-3 rounded-xl outline-none text-sm" placeholder="Xabar..." value={msg} onChange={e => setMsg(e.target.value)} />
            <button onClick={() => { onSendMsg(msg); setMsg(''); }} className="p-3 gold-gradient text-white rounded-xl active:scale-95 transition-transform"><Send size={18} /></button>
          </div>
        </div>
        <button onClick={() => onBuy(sz)} className="w-full py-5 gold-gradient text-white font-bold rounded-2xl shadow-xl flex items-center justify-center space-x-2 active:scale-95 transition-transform">
          <ShoppingCart size={20} /> <span>{t.buy}</span>
        </button>
      </div>
    </div>
  );
};

