const AdminPanel = ({ onAdd, onCancel, t }: any) => {
  const [fd, setFd] = useState({ name: '', price: 0, desc: '', sizes: 'S, M, L, XL' });
  const [imgs, setImgs] = useState<string[]>([]);
  const [vids, setVids] = useState<string[]>([]);

  const imgInputRef = useRef<HTMLInputElement>(null);
  const vidInputRef = useRef<HTMLInputElement>(null);

  const handleImgs = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    files.forEach((file: File) => {
      const reader = new FileReader();
      reader.onloadend = () => setImgs(prev => [...prev, reader.result as string].slice(0, 5));
      reader.readAsDataURL(file);
    });
  };

  const handleVids = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    files.forEach((file: File) => {
      const reader = new FileReader();
      reader.onloadend = () => setVids(prev => [...prev, reader.result as string].slice(0, 3));
      reader.readAsDataURL(file);
    });
  };

  const save = () => {
    if (!fd.name || !fd.price) {
      alert("Nom va narxni kiriting!");
      return;
    }
    if (imgs.length < 1) {
      alert("Kamida 1 ta rasm yuklang!");
      return;
    }
    if (vids.length < 1) {
      alert("Kamida 1 ta video yuklang!");
      return;
    }

    const newProduct = { 
      id: 'P-' + Date.now(), 
      name: fd.name, 
      pinduoduoPrice: fd.price, 
      description: fd.desc, 
      sizes: fd.sizes.split(',').map(s => s.trim()).filter(s => s), 
      images: imgs, 
      videos: vids, 
      category: 'Shop', 
      rating: 5, 
      salesCount: 0, 
      seller: { name: 'Ruslan Shop', avatar: '', rating: 5, description: '' } 
    };

    onAdd(newProduct);
  };

  return (
    <div className="p-8 space-y-6 pb-24">
      <div className="flex items-center space-x-4">
        <button onClick={onCancel} className="p-2 bg-gray-100/10 rounded-xl active:scale-90 transition-transform"><ChevronLeft size={20}/></button>
        <h2 className="text-2xl font-bold tracking-tight">Maxsulot qo'shish</h2>
      </div>

      <div className="space-y-4">
        <label className="text-xs font-bold text-gray-400 uppercase tracking-widest">Rasmlar (Min 1 ta)</label>
        <div className="grid grid-cols-3 gap-2">
          {imgs.map((im, i) => (
            <div key={i} className="relative aspect-square shadow-sm animate-in zoom-in-50">
              <img src={im} className="w-full h-full object-cover rounded-xl" />
              <button onClick={() => setImgs(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-1 right-1 p-1 bg-red-500 text-white rounded-full transition-transform active:scale-75"><X size={10}/></button>
            </div>
          ))}
          {imgs.length < 5 && (
            <button onClick={() => imgInputRef.current?.click()} className="aspect-square bg-gray-100/10 border-2 border-dashed border-gray-400/20 rounded-xl flex items-center justify-center text-gray-400 hover:bg-gray-100/20 active:scale-95 transition-all">
              <Camera size={24} />
            </button>
          )}
        </div>
        <input type="file" ref={imgInputRef} multiple className="hidden" accept="image/*" onChange={handleImgs} />
      </div>

      <div className="space-y-4">
        <label className="text-xs font-bold text-gray-400 uppercase tracking-widest">Videolar (Min 1 ta)</label>
        <div className="grid grid-cols-3 gap-2">
          {vids.map((vd, i) => (
            <div key={i} className="relative aspect-square bg-black rounded-xl overflow-hidden shadow-sm animate-in zoom-in-50">
              <video src={vd} className="w-full h-full object-contain" />
              <button onClick={() => setVids(prev => prev.filter((_, idx) => idx !== i))} className="absolute top-1 right-1 p-1 bg-red-500 text-white rounded-full z-10 transition-transform active:scale-75"><X size={10}/></button>
            </div>
          ))}
          {vids.length < 3 && (
            <button onClick={() => vidInputRef.current?.click()} className="aspect-square bg-gray-100/10 border-2 border-dashed border-gray-400/20 rounded-xl flex items-center justify-center text-gray-400 hover:bg-gray-100/20 active:scale-95 transition-all">
              <Video size={24} />
            </button>
          )}
        </div>
        <input type="file" ref={vidInputRef} multiple className="hidden" accept="video/*" onChange={handleVids} />
      </div>

      <div className="space-y-4">
        <input className="w-full bg-gray-100/10 border border-gray-200/20 p-4 rounded-xl outline-none focus:border-amber-500/50 transition-colors" placeholder="Mahsulot nomi" value={fd.name} onChange={e=>setFd({...fd, name: e.target.value})} />
        <input type="number" className="w-full bg-gray-100/10 border border-gray-200/20 p-4 rounded-xl outline-none focus:border-amber-500/50 transition-colors" placeholder="Narxi ($)" value={fd.price} onChange={e=>setFd({...fd, price: Number(e.target.value)})} />
        <textarea className="w-full bg-gray-100/10 border border-gray-200/20 p-4 rounded-xl outline-none h-24 focus:border-amber-500/50 transition-colors" placeholder="Tavsif (ixtiyoriy)" value={fd.desc} onChange={e=>setFd({...fd, desc: e.target.value})} />
        <input className="w-full bg-gray-100/10 border border-gray-200/20 p-4 rounded-xl outline-none focus:border-amber-500/50 transition-colors" placeholder="O'lchamlar (masalan: S, M, L)" value={fd.sizes} onChange={e=>setFd({...fd, sizes: e.target.value})} />
      </div>

      <button onClick={save} className="w-full py-5 gold-gradient text-white font-bold rounded-2xl shadow-xl active:scale-95 uppercase tracking-widest text-sm transition-transform">Do'konga joylash</button>
    </div>
  );
};

